    n = len(s)

    # x must be an Armstrong number (narcissistic number)
    if sum(int(d)**n for d in s) != x:
        return False

    # Must have exactly 3 digits
    if n != 3:
        return False

    # All digits must be different
    if len(set(s)) != 3:
        return False

